import React, { useContext } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "../styles/Navbar.css";
import { ThemeContext } from "../context/ThemeContext";

const Navbar = () => {
    const navigate = useNavigate();
    const { theme, toggleTheme } = useContext(ThemeContext);

    const handleScrollToSection = (e, sectionId) => {
        e.preventDefault();
        navigate("/");
        setTimeout(() => {
            const section = document.getElementById(sectionId);
            if (section) {
                section.scrollIntoView({ behavior: "smooth" });
            }
        }, 100);
    };

    const handleThemeChange = (e) => {
        const newTheme = e.target.value;
        const themes = ["light", "dark", "blue", "green", "purple"];
        if (themes.includes(newTheme)) {
            localStorage.setItem("theme", newTheme);
            document.documentElement.setAttribute("data-theme", newTheme);
            window.location.reload(); // refresh to re-initialize ThemeContext with new theme
        }
    };

    return (
        <nav className="navbar">
            <div className="logo">ActAware</div>
            <ul className="nav-links">
                <li>
                    <a href="/home" onClick={(e) => handleScrollToSection(e, "body-section")}>Home</a>
                </li>
                <li>
                    <a href="/body" onClick={(e) => handleScrollToSection(e, "body-section")}>About Us</a>
                </li>
                <li>
                    <a href="/blogs" onClick={(e) => handleScrollToSection(e, "blogs-section")}>Feedback</a>
                </li>
                <li>
                    <a href="/blogs" onClick={(e) => handleScrollToSection(e, "blogs-section")}>Sign Language</a>
                </li>
                <li>
                    <select className="theme-dropdown" value={theme} onChange={handleThemeChange}>
                        <option value="light">☀️ Light</option>
                        <option value="dark">🌙 Dark</option>
                        <option value="blue">🔵 Blue</option>
                        <option value="green">🟢 Green</option>
                        <option value="purple">🟣 Purple</option>
                    </select>
                </li>
                <NavLink to="/signup">
                    <button className="signup-btn">Sign Up</button>
                </NavLink>
            </ul>
        </nav>
    );
};

export default Navbar;
